text.regex:
(?isx)\A
# The answer must affirmatively identify the Personal Information Update route.
(?=
  .*
  (?:
    \b(?:use|complete|submit|file|start|fill[\s_-]+out|access|follow|choose|select)\b
    [^.!?\n]{0,140}
    \bpersonal[\s_-]+information[\s_-]+update\b
    |
    \b(?:correct|official|appropriate|right)\b
    [^.!?\n]{0,80}
    \b(?:place|destination|route|process|procedure|form|request)\b
    [^.!?\n]{0,100}
    \bpersonal[\s_-]+information[\s_-]+update\b
    |
    \bpersonal[\s_-]+information[\s_-]+update\b
    [^.!?\n]{0,90}
    \b(?:request|form|process|procedure|route|destination)\b
  )
)

# Reject answers that negate the correct process.
(?!.*\b(?:do[\s_-]+not|don['’]?t|avoid|wrong|incorrect|not[\s_-]+the[\s_-]+correct)\b
      [^.!?\n]{0,100}\bpersonal[\s_-]+information[\s_-]+update\b)

# Reject affirmative navigation or submission instructions to nearby generic portals.
# Explicit negations such as "do not use Student eForms" remain acceptable.
(?!.*(?:\A|[.!?\n]\s*)
      (?:(?!\b(?:do[\s_-]+not|don['’]?t|avoid|never)\b)[^.!?\n]){0,60}
      \b(?:use|go[\s_-]+to|navigate[\s_-]+to|open|select|click|choose|find|access|submit|complete|track)\b
      (?:(?!\b(?:not|instead[\s_-]+of|rather[\s_-]+than)\b)[^.!?\n]){0,140}
      \b(?:student[\s_-]*e[\s_-]*forms?|e[\s_-]*forms?[\s_-]+portal|my[\s_-]+academics|petitions?[\s_-]*(?:&|and)?[\s_-]*forms|browse[\s_-]+available[\s_-]+forms|stanfordyou|alumni(?:[\s_-]+association)?[\s_-]+my[\s_-]+account)\b)

# Reject calling the Personal Information Update request an eForm.
(?!.*\bpersonal[\s_-]+information[\s_-]+update\b
      (?:(?!\bnot\b)[^.!?\n]){0,40}
      \be[\s_-]*form\b)
(?!.*\be[\s_-]*form\b
      (?:(?!\bnot\b)[^.!?\n]){0,40}
      \bpersonal[\s_-]+information[\s_-]+update\b)

# Reject statements that bind the Personal Information Update process to Axess,
# Student eForms, StanfordYou, or the alumni account.
(?!.*\bpersonal[\s_-]+information[\s_-]+update\b
      (?:(?!\b(?:not|instead[\s_-]+of|rather[\s_-]+than)\b)[^.!?\n]){0,120}
      \b(?:via|through|inside|within|in|on|as|is|available[\s_-]+in|submitted[\s_-]+through)\b
      (?!\s*not\b)
      (?:(?!\b(?:not|instead[\s_-]+of|rather[\s_-]+than)\b)[^.!?\n]){0,100}
      \b(?:(?:student[\s_-]*e[\s_-]*forms?|e[\s_-]*forms?[\s_-]+portal|my[\s_-]+academics|petitions?[\s_-]*(?:&|and)?[\s_-]*forms|browse[\s_-]+available[\s_-]+forms|stanfordyou|alumni(?:[\s_-]+association)?[\s_-]+my[\s_-]+account)|axess)\b)

# Reject an explicitly wrong "correct destination" claim.
(?!.*\b(?:correct|right|official)\b
      [^.!?\n]{0,80}
      \b(?:place|destination|route|portal|process)\b
      (?:(?!\b(?:not|instead[\s_-]+of|rather[\s_-]+than)\b)[^.!?\n]){0,100}
      \b(?:student[\s_-]*e[\s_-]*forms?|e[\s_-]*forms?[\s_-]+portal|my[\s_-]+academics|petitions?[\s_-]*(?:&|and)?[\s_-]*forms|browse[\s_-]+available[\s_-]+forms|stanfordyou|alumni(?:[\s_-]+association)?[\s_-]+my[\s_-]+account)\b)

# Reject self-service routing of the legal/primary name through Axess My Information.
(?!.*\b(?:use|update|change|edit|open|go[\s_-]+to)\b
      (?:(?!\b(?:not|instead[\s_-]+of|rather[\s_-]+than)\b)[^.!?\n]){0,120}
      \b(?:axess[^.!?\n]{0,40}my[\s_-]+information|my[\s_-]+information[^.!?\n]{0,40}axess)\b
      [^.!?\n]{0,120}
      \b(?:(?:legal|primary)(?:\s*[/(-]\s*(?:legal|primary)\s*\)?)?\s+name|name[\s_-]+of[\s_-]+record)\b)
(?!.*\b(?:(?:legal|primary)(?:\s*[/(-]\s*(?:legal|primary)\s*\)?)?\s+name|name[\s_-]+of[\s_-]+record)\b
      [^.!?\n]{0,120}
      \b(?:use|update|change|edit|open|go[\s_-]+to)\b
      (?:(?!\b(?:not|instead[\s_-]+of|rather[\s_-]+than)\b)[^.!?\n]){0,120}
      \b(?:axess[^.!?\n]{0,40}my[\s_-]+information|my[\s_-]+information[^.!?\n]{0,40}axess)\b)
(?!.*(?:\A|[.!?\n]\s*)
      (?:(?!\b(?:do[\s_-]+not|don['’]?t|avoid|never)\b)[^.!?\n]){0,60}
      \b(?:use|update|change|edit)\b
      (?:(?!\b(?:not|instead[\s_-]+of|rather[\s_-]+than)\b)[^.!?\n]){0,100}
      \b(?:(?:legal|primary)(?:\s*[/(-]\s*(?:legal|primary)\s*\)?)?\s+name|name[\s_-]+of[\s_-]+record)\b
      (?:(?!\b(?:not|instead[\s_-]+of|rather[\s_-]+than)\b)[^.!?\n]){0,120}
      \b(?:axess[^.!?\n]{0,40}my[\s_-]+information|my[\s_-]+information[^.!?\n]{0,40}axess)\b)

.*\Z
